const $=s=>document.querySelector(s);const $$=s=>Array.from(document.querySelectorAll(s));
const stages=['TARGET','EMIT','FILTER','ATLAS','TEST-PLAN','EVAL','INSERT','PROMOTE'];
const files={contract:{name:'contract.json',body:{status:'READY',objective:'Mission contract waiting for first cycle.',authority:'DENY'}},progress:{name:'progress.md',body:'# progress\n- Awaiting first RSI cycle.\n- Search control is advisory.\n- Outcome authority remains mechanical.'},state:{name:'rsi_state.json',body:{cycle_index:0,eci:'E0',drift_sentinel:'armed',archive:'append-only',authority:'DENY'}},dossier:{name:'dossier.md',body:'# RSIDossier\nNo candidate admitted. No promotion without evidence, baselines, replay, persistence, validator review, and human boundary.'}};
let state={stage:0,cycle:0,eci:'E0',authority:'DENY',dossiers:0,cards:0,baselines:0,shocks:0,proofDebt:100,trace:['00 · Control room initialized. No external action. No network. No wallet.','01 · Mission contract awaiting first gate.'],move37:false,quarantined:false};
function clamp(n){return Math.max(0,Math.min(100,Math.round(n)))}
function addTrace(t){state.trace.push(t);if(state.trace.length>24)state.trace.shift();renderTrace()}
function stageText(){const s=stages[state.stage];return {TARGET:'TARGET allocates exploration pressure without granting authority.',EMIT:'EMIT creates candidate cards under contract, role, tool, and evidence boundaries.',FILTER:'FILTER routes weak or risky candidates to reject, probe, refine, or quarantine. No insertion authority.',ATLAS:'ATLAS records mechanism links, contradictions, side effects, and causal bridges.', 'TEST-PLAN':'TEST‑PLAN builds falsification ladders and cheapest valid probes.',EVAL:'EVAL compares against incumbent, neighbor, null, and current-stack baselines.',INSERT:'INSERT writes only proof-cleared candidates into append-only archive state.',PROMOTE:'PROMOTE packages the dossier for human review. Deployment authority remains outside this public demo.'}[s]}
function updateGates(){const novelty=+$('#novelty').value, adv=+$('#advantage').value, ev=+$('#evidence').value, risk=+$('#risk').value; state.proofDebt=clamp(100-ev*.72-adv*.18+Math.max(0,risk-42)*.4); state.eci=ev>82?'E4':ev>64?'E3':ev>44?'E2':ev>20?'E1':'E0'; const riskOk=risk<70; const baselineOk=state.baselines>=3&&adv>54; const persistenceOk=state.shocks>=2&&adv>52&&risk<62; const evidenceOk=['E2','E3','E4'].includes(state.eci); const promote=riskOk&&baselineOk&&persistenceOk&&evidenceOk&&!state.quarantined&&state.stage>=7; state.authority=promote?'REVIEW':'DENY'; const map={risk:[riskOk?'ALLOW':'BLOCK',riskOk?'pass':'block'],evidence:[state.eci+(evidenceOk?' · executed':' · probe'),evidenceOk?'pass':''],baseline:[baselineOk?'PASS':'PENDING',baselineOk?'pass':''],replay:['READY','pass'],persistence:[persistenceOk?'PASS':'PENDING',persistenceOk?'pass':''],human:[promote?'REVIEW REQUIRED':'REQUIRED',promote?'pass':'']}; $$('.gate').forEach(g=>{const [txt,cls]=map[g.dataset.gate];g.querySelector('b').textContent=txt;g.className='gate '+cls}); $('#authority').textContent=state.authority; $('#heroState').textContent=state.authority==='REVIEW'?'REVIEW READY':state.quarantined?'QUARANTINED':'RUNNING'; $('#eciLevel').textContent=state.eci; $('#proofDebt').textContent=state.proofDebt; $('#verdict').textContent=state.authority==='REVIEW'?'REVIEW READY · Dossier package is ready for human authority.':state.quarantined?'QUARANTINED · Candidate blocked pending review.':'DENY · Not enough executed evidence for promotion.'; return {novelty,adv,ev,risk,promote}}
function render(){updateGates(); $('#cycleIndex').textContent=state.cycle; $('#dossierCount').textContent=state.dossiers; $('#cards').textContent=state.cards; $('#baselines').textContent=state.baselines; $('#shocks').textContent=state.shocks; $$('.stage').forEach((el,i)=>{el.classList.toggle('active',i===state.stage);el.classList.toggle('done',i<state.stage)}); $('#stageNarrative').textContent=stageText(); renderFile(); renderTrace()}
