function renderFile(){const active=$('.tab.active')?.dataset.file||'contract'; const preset=$('#preset')?.value||'proof-site'; const objective=$('#objective')?.value.trim()||'No objective set.'; const payload={contract:{status:state.authority,objective,preset,done_condition:'RSIDossier + human review boundary',public_safe:true},progress:`# progress\n- cycle_index: ${state.cycle}\n- stage: ${stages[state.stage]}\n- ECI: ${state.eci}\n- proof_debt: ${state.proofDebt}\n- authority: ${state.authority}\n- move37_candidate: ${state.move37}\n- quarantined: ${state.quarantined}`,state:{cycle_index:state.cycle,current_stage:stages[state.stage],eci:state.eci,authority:state.authority,archive:'append-only',drift_sentinel:'armed',cards:state.cards,baselines:state.baselines,shock_tests:state.shocks},dossier:`# RSIDossier\nstatus: ${state.authority}\ncycle: ${state.cycle}\nECI: ${state.eci}\nclaim boundary: public-safe demonstration only\nnext step: human review before any stronger claim.`}; const v=payload[active]; $('#fileView').textContent=typeof v==='string'?v:JSON.stringify(v,null,2)}
function advance(){state.stage=(state.stage+1)%stages.length; if(state.stage===0)state.cycle++; if(state.stage>=1)state.cards=Math.max(state.cards,1+state.cycle); if(state.stage>=5)state.baselines=Math.max(state.baselines,Math.min(4,state.stage-3)); if(state.stage>=7)state.dossiers=Math.max(state.dossiers,1); addTrace(`${String(state.cycle).padStart(2,'0')} · ${stages[state.stage]} gate advanced. ${stageText()}`); render()}
function runFull(){for(let i=0;i<8;i++)advance(); $('#evidence').value=Math.max(+$('#evidence').value,72); $('#advantage').value=Math.max(+$('#advantage').value,68); $('#risk').value=Math.min(+$('#risk').value,36); state.baselines=4;state.shocks=Math.max(state.shocks,2);state.dossiers=1; addTrace('DONE · RSIDossier assembled for review. Public demo stops before authority.'); render()}
function move37(){state.move37=true;state.cards+=2;$('#novelty').value=Math.max(+$('#novelty').value,88); state.shocks=Math.max(state.shocks,1); addTrace('MOVE-37 · High-novelty candidate detected. Burden of proof increased: reproduce, stress, persist, dossier.'); render()}
function restart(){state.cycle++;state.stage=0;state.quarantined=false;addTrace(`RESTART · cycle_index ${state.cycle}; manifest replayed; state preserved outside context.`);render()}
function quarantine(){state.quarantined=true;state.authority='DENY';addTrace('QUARANTINE · Candidate blocked. Minimal hash, reason, and boundary retained; no promotion.');render()}
function copyBrief(){const brief=`GoalOS Loop → RSI Control Room\n\nObjective: ${$('#objective').value.trim()}\nState: ${state.authority}\nCycle: ${state.cycle}\nStage: ${stages[state.stage]}\nECI: ${state.eci}\nProof debt: ${state.proofDebt}\n\nRule: search may allocate attention; only risk, evidence, baseline, persistence, replay, validator, and human boundary can promote.\n\nBoundary: browser-local demo; no wallet, no network, no user data, no production authority.`; const box=document.createElement('textarea'); box.value=brief; box.setAttribute('readonly',''); box.style.position='fixed'; box.style.left='-9999px'; document.body.appendChild(box); box.select(); try{document.execCommand('copy')}catch(e){} box.remove(); addTrace('COPY · Review brief copied locally when the browser permits it.');}
function download(){const docket={type:'RSIDossier',release:'v51-loop-to-rsi-control-room',generatedAt:new Date().toISOString(),publicSafe:true,noWallet:true,noNetwork:true,noUserDataWanted:true,objective:$('#objective').value.trim(),preset:$('#preset').value,cycle:state.cycle,stage:stages[state.stage],eci:state.eci,authority:state.authority,proofDebt:state.proofDebt,cards:state.cards,baselines:state.baselines,shockTests:state.shocks,move37:state.move37,quarantined:state.quarantined,trace:state.trace,claimBoundary:'public-safe demonstration only; no achieved AGI, ASI, SOTA, autonomous authority, or production deployment claim'}; const blob=new Blob([JSON.stringify(docket,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='goalos-loop-to-rsi-control-room-rsidossier.json'; a.click(); URL.revokeObjectURL(a.href); addTrace('EXPORT · RSIDossier JSON emitted locally from browser state.');}
function initField(){const c=$('#field'); if(!c)return; const ctx=c.getContext('2d'); let w,h,pts=[]; function size(){w=c.width=innerWidth;h=c.height=innerHeight;pts=Array.from({length:90},()=>({x:Math.random()*w,y:Math.random()*h,r:Math.random()*2+0.5,v:Math.random()*0.35+0.08,a:Math.random()*6.28}))} function draw(){ctx.clearRect(0,0,w,h);for(const p of pts){p.y-=p.v;if(p.y< -10)p.y=h+10;p.a+=0.01;ctx.globalAlpha=.45+Math.sin(p.a)*.25;ctx.fillStyle=p.r>1.7?'#ffe67a':'#68ffd1';ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,6.28);ctx.fill();ctx.globalAlpha=.16;ctx.fillRect(p.x,p.y+4,1,24)}requestAnimationFrame(draw)}size();addEventListener('resize',size,{passive:true});draw()}
$$('[data-action]').forEach(b=>b.addEventListener('click',()=>({advance,runFull,move37,restart,quarantine,download,copyBrief})[b.dataset.action.replace(/-([a-z])/g,(_,c)=>c.toUpperCase())]?.())); $$('.stage').forEach((b,i)=>b.addEventListener('click',()=>{state.stage=i;addTrace(`JUMP · ${stages[i]} inspected.`);render()})); $$('.tab').forEach(t=>t.addEventListener('click',()=>{$$('.tab').forEach(x=>x.classList.remove('active'));t.classList.add('active');renderFile()})); $$('input,select,textarea').forEach(x=>x.addEventListener('input',render)); initField(); render();